using System.Net.Sockets;

using Sharpmine.Server.Protocol.Packets.Status.Clientbound;

namespace Sharpmine.Server.Protocol.Packets.Status.Serverbound;

public partial record StatusRequestPacket
{

    public Task DeserializeContentAsync(
        NetworkStream stream,
        BinaryReader reader,
        CancellationToken cancellationToken) => Task.CompletedTask;

    public Task ProcessAsync(ClientHandler handler, NetworkStream stream, BinaryReader reader, BinaryWriter writer, CancellationToken cancellationToken)
    {
        var status = new ServerStatus
        {
            Version = new ServerStatus.StatusVersion("1.21.10", 773),
            Players = new ServerStatus.StatusPlayers(1337, 2)
            {
                Sample =
                [
                    new ServerStatus.StatusPlayers.Player("Deswegen", Guid.Parse("7e5abf92-0bf6-4b21-8c12-ad9a32720f3b")),
                    new ServerStatus.StatusPlayers.Player("Yes_Mc", Guid.Parse("ae2f02a6-001e-46b6-a659-5e016cf6e8e5"))
                ],
            },
            Description = new ServerStatus.StatusDescription("Heya"),
            Favicon = "data:image/png;base64,",
        };

        var response = new StatusResponsePacket(status);
        return handler.PacketSender.SendAsync(response, stream, writer, cancellationToken);
    }

}